import{_ as t,o as a,c as d,ag as s}from"./chunks/framework.Lq6hU67C.js";const p=JSON.parse('{"title":"Handle identity","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/handle-identity.md","filePath":"concepts/handle-identity.md"}'),o={name:"concepts/handle-identity.md"};function r(i,e,l,n,c,h){return a(),d("div",null,[...e[0]||(e[0]=[s('<h1 id="handle-identity" tabindex="-1">Handle identity <a class="header-anchor" href="#handle-identity" aria-label="Permalink to &quot;Handle identity&quot;">​</a></h1><p>Addressables Leak Detector correlates handles using <strong>public API only</strong> — no reflection on private fields such as <code>m_Version</code> or <code>m_InternalOp</code>.</p><h2 id="identity-fields" tabindex="-1">Identity fields <a class="header-anchor" href="#identity-fields" aria-label="Permalink to &quot;Identity fields&quot;">​</a></h2><table tabindex="0"><thead><tr><th>API</th><th>Use</th></tr></thead><tbody><tr><td><code>GetHashCode()</code></td><td>Primary key for live registry</td></tr><tr><td><code>Equals()</code></td><td>Equality comparison</td></tr><tr><td><code>IsValid()</code></td><td>Whether handle still references an operation</td></tr><tr><td><code>DebugName</code></td><td>Human-readable asset/scene label in UI</td></tr></tbody></table><h2 id="struct-copies" tabindex="-1">Struct copies <a class="header-anchor" href="#struct-copies" aria-label="Permalink to &quot;Struct copies&quot;">​</a></h2><p><code>AsyncOperationHandle</code> is a <strong>struct</strong>. ILPP captures load at the call site and immediately stores the returned value in a local variable before subscribing to lifecycle events. Subscribing on the wrong copy would miss <code>Completed</code> / <code>Destroyed</code>.</p><p>The injector follows the rule: <strong>never <code>Dup</code> immediately after an Addressables load <code>call</code></strong> — use <code>stloc</code> + <code>ldloc</code> instead.</p><h2 id="isvalid-caveat" tabindex="-1">IsValid() caveat <a class="header-anchor" href="#isvalid-caveat" aria-label="Permalink to &quot;IsValid() caveat&quot;">​</a></h2><p><code>IsValid()</code> can return <code>true</code> after <code>Release()</code> when the same <code>AssetReference</code> is used elsewhere. Use it for identity checks, not as the sole leak verdict.</p><h2 id="reload-same-address" tabindex="-1">Reload same address <a class="header-anchor" href="#reload-same-address" aria-label="Permalink to &quot;Reload same address&quot;">​</a></h2><p>Loading the same address twice creates <strong>distinct</strong> handles with different hash codes. Live Leaks may show multiple entries or <strong>RedundantLoad</strong> severity when both are live.</p><h2 id="related-call-sites" tabindex="-1">Related call sites <a class="header-anchor" href="#related-call-sites" aria-label="Permalink to &quot;Related call sites&quot;">​</a></h2><p>The detail panel can show other live handles for the same asset key, helping you find duplicate loads from different scripts.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./layers-and-event-log.html">Layers and event log</a></li><li><a href="./../reference/il-limitations.html">IL patterns and limitations</a></li></ul>',15)])])}const m=t(o,[["render",r]]);export{p as __pageData,m as default};
